INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1940', 'San Miguel de Salinas : superbes appartements modernes en 3 chambres', '', '', 'Découvrez ces magnifiques appartements modernes situés dans une résidence calme et verdoyante, à seulement 500 mètres du c?ur de San Miguel de Salinas. San Miguel de Salinas est un charmant village typique de la Costa Blanca, idéal pour vivre toute l''année grâce à son climat agréable et son atmosphère dynamique. Les plages d''Orihuela Costa se trouvent à 7 km et de nombreux parcours de golf sont situés dans les environs proches. Avec 3 chambres et 2 salles de bains, ces appartements allient confort et fonctionnalité, offrant des espaces de vie lumineux grâce à un design soigné. Les appartements disposent d?un grand salon donnant sur une belle terrasse de 23 m², idéale pour profiter des journées ensoleillées, d''une cuisine entièrement équipée d''électroménagers, d''un système de climatisation centralisée, d''une place de parking privée ainsi que d''une cave en sous-sol. Le complexe résidentiel se distingue par sa grande zone de jardin paysager et ses 3 piscines communes, parfaites pour se détendre tout en étant entouré de verdure. L''architecture du projet assure de grandes distances entre chaque bloc, garantissant une intimité et un cadre de vie agréable. Prix : A partir de 276.000 ? hors frais Dernier étage avec solarium : à partir de 390.000 ? hors frais', '', '', 276000, 'san-miguel-de-salinas-superbes-appartements-modernes-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1945', 'Pilar de la Horadada : superbes maisons 3 chambres', '', '', 'Découvrez ce tout nouveau complexe résidentiel situé à Pilar de la Horadada, un lieu privilégié sur la Costa Blanca, à seulement 2 km des plages. La résidence offre des espaces communs de qualité, comprenant une piscine, des jardins paysagers et une aire de jeux pour enfants, faisant de cet endroit un lieu parfait pour toute la famille. La résidence compte des maisons 3 chambres, des appartements 3 chambres sur 3 niveaux, ou des appartements 3 chambres sur 2 niveaux. Les maisons 3 chambres sont agencées comme suit : Rez-de-chaussée: cuisine ouverte, salon, 1 chambre et 1 salle de bains, terrasse. 1er étage: 2 chambres, 1 salle de bains, terrasse 2ème étage : solarium Chaque propriété est pensée dans un style moderne et fonctionnel, offrant des matériaux de qualité et des finitions contemporaines: Pilar de la Horadada est une ville côtière située au sud de la Costa Blanca, bénéficiant d''un climat agréable et d?une qualité de vie remarquable. Sa rue principale, vivante et dynamique, regorge de commerces, supermarchés, restaurants et autres services essentiels. À seulement 5 minutes en voiture, vous découvrirez les magnifiques plages de Torre de la Horadada et de Mil Palmeras, idéales pour profiter du soleil, du sable doré et de la mer. La région offre également de nombreuses pistes cyclables, des sentiers de randonnée et des possibilités d''activités sportives. Distances clés : - Terrain de golf Lo Romero ? 5 km (10 minutes en voiture) - Aéroport de Corvera (Murcie) ? 40 km (40 minutes en voiture) - Aéroport d''Alicante ? 55 km (55 minutes en voiture) - Centre commercial Zenia Boulevard ? 15 km (15 minutes en voiture) - Marina Torre de la Horadada ? 3 km (5 minutes en voiture) Prix : De 299.900 ? à 369.900 ? hors frais Place de parking intérieure Inclus: électroménagers Fin des travaux : octobre 2026 * Les images intérieures sont celles de phases précédentes', '', '', 299900, 'pilar-de-la-horadada-superbes-maisons-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1947', 'San Miguel de Salinas : beaux appartements 2 chambres complètement meublés et équipés !', '', '', 'A San Miguel de Salinas, nouvelle résidence alliant design contemporain, espaces généreux et prestations haut de gamme. Située à proximité immédiate du centre-ville, cette résidence vous offre un cadre de vie idéal dans l?une des régions les plus agréables de la Costa Blanca. San Miguel de Salinas surplombe les lagunes de Torrevieja et La Mata et séduit par son environnement naturel, son ambiance familiale et ses services de proximité. Un lieu idéal pour vivre à l?année ou profiter de vacances en toute sérénité. Les appartements lumineux, répartis sur 7 étages, disposent de 2 chambres, d''une cuisine entièrement équipée, de terrasses spacieuses et d?un agencement optimisé. Les parties communes sont conçues pour le bien-être de toute la famille : - Piscines séparées pour adultes et enfants - Espaces verts paysagers - Aire de jeux pour enfants - Zone de pétanque Située dans un environnement calme et bien desservi, la résidence se trouve : - À seulement 7 km des golfs de Las Colinas et Campoamor - À 10 km des plages d?Orihuela Costa et Torrevieja - À 9 km du centre commercial Zenia Boulevard - À 50 km de l?aéroport d?Alicante - À 55 km de l?aéroport de Murcie Corvera Prix: à partir de 224.000 ? hors frais TOUT INCLUS: meubles, électroménagers, climatisation, place de parking, remise. Fin des travaux: décembre 2026 ou avril 2027 * Les photos intérieures sont celles d''une autre résidence du même constructeur', '', '', 224000, 'san-miguel-de-salinas-beaux-appartements-2-chambres-completement-meubles-et-equipes', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1948', 'San Fulgencio : beaux appartements 2 chambres dans une nouvelle résidence', '', '', 'Nouvelle résidence située à San Fulgencio, un charmant village espagnol au c?ur de la Costa Blanca. Ce complexe propose des appartements 2 chambres, conçus pour offrir confort, design contemporain et efficacité énergétique dans un environnement calme et verdoyant. Vous pourrez choisir entre : - Rez-de-chaussée avec jardin privatif - Penthouses avec solarium privé Tous les logements disposent d''une place de parking Belle piscine commune et jardins paysagers. Distances clés : - Aéroport d?Alicante-Elche ? 30 km (30 min) - Plage de La Marina ? 7 km (10 min) - Guardamar del Segura ? 10 km (12 min) - Golf La Marquesa (Ciudad Quesada) ? 6 km (8 min) - Torrevieja ? 18 km (20 min) Prix : à partir de 233.900 ? hors frais Fin des travaux: avril 2027', '', '', 233900, 'san-fulgencio-beaux-appartements-2-chambres-dans-une-nouvelle-residence', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1951', 'Aspe: appartements 2 chambres dans un golf exclusif', '', '', 'Cette nouvelle résidence est située das un superbe golf, idéalement situé dans la province d''Alicante, à proximité d''Aspe et de Elche, à 20 minutes des belles plages de la Méditerranée et à seulement 15 minutes de l''aéroport d''Alicante. Un golf exclusif connu pour ses paysages magnifiques et ses équipements de luxe. Le complexe de golf offre un parcours 18 trous stimulant qui s''intègre parfaitement dans l''environnement naturel, avec une vue magnifique sur les montagnes et les vallées environnantes. Outre le golf, vous trouverez diverses installations, notamment un club-house avec un restaurant et un bar, un pro-shop et de nombreuses installations d''entraînement. La résidence se compose de 3 bâtiments, avec un total de 60 appartements. La première phase compte 24 appartements 2 ou 3 chambres. Les appartements du rez-de-chaussée disposent de terrasses à l''avant et à l''arrière et de grands jardins, tandis que ceux du dernier étage jouissent d''un solarium. Les appartements de l''étage intermédiaire disposent de grandes terrasses. Tous les appartements disposent d''une place de parking souterrain et d''un débarras. Les espaces communs sont équipés de deux piscines (dont une peu profonde pour les enfants), deux jacuzzis, une aire de jeux, un espace sportif extérieur, un espace de coworking et de beaux jardins paysagers. Prix: Appartements 2 chambres: à partir de 255.000 ? hors frais Livraison: 2T2027', '', '', 255000, 'aspe-appartements-2-chambres-dans-un-golf-exclusif', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1952', 'Aspe: appartements 3 chambres dans un golf exclusif', '', '', 'Cette nouvelle résidence est située das un superbe golf, idéalement situé dans la province d''Alicante, à proximité d''Aspe et de Elche, à 20 minutes des belles plages de la Méditerranée et à seulement 15 minutes de l''aéroport d''Alicante. Un golf exclusif connu pour ses paysages magnifiques et ses équipements de luxe. Le complexe de golf offre un parcours 18 trous stimulant qui s''intègre parfaitement dans l''environnement naturel, avec une vue magnifique sur les montagnes et les vallées environnantes. Outre le golf, vous trouverez diverses installations, notamment un club-house avec un restaurant et un bar, un pro-shop et de nombreuses installations d''entraînement. La résidence se compose de 3 bâtiments, avec un total de 60 appartements. La première phase compte 24 appartements 2 ou 3 chambres. Les appartements du rez-de-chaussée disposent de terrasses à l''avant et à l''arrière et de grands jardins, tandis que ceux du dernier étage jouissent d''un solarium. Les appartements de l''étage intermédiaire disposent de grandes terrasses. Tous les appartements disposent d''une place de parking souterrain et d''un débarras. Les espaces communs sont équipés de deux piscines (dont une peu profonde pour les enfants), deux jacuzzis, une aire de jeux, un espace sportif extérieur, un espace de coworking et de beaux jardins paysagers. Prix: Appartements 3 chambres: à partir de 340.000 ? hors frais Livraison: 2T2027', '', '', 340000, 'aspe-appartements-3-chambres-dans-un-golf-exclusif', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1954', 'Las Colinas: superbes appartements 3 chambres dans un golf exclusif', '', '', 'Le golf de Las Colinas et son gigantesque domaine offrent un calme et un mode de vie à part. Lovées dans une nature préservée, ces résidences bénéficient d''une surveillance 24h/24. Plusieurs restaurants, un clubhouse, des terrains de tennis, un centre wellness sont présents dans le domaine. Le resort s''étend sur 350 hectares et offre des panoramas uniques sur la mer, la réserve naturelle et le golf. La résidence se compose de deux bâtiments de petite taille, entourés de jardins paysagers luxuriants, qui offrent calme et intimité. Les appartements jouissent d''incroyables vues sur le golf, et sur la mer pour certains. Les appartements proposent 3 chambres, 2 salles de bains, une cuisine ouverte donnant sur le vaste living avec baies vitrées vers la grande terrasse. Chaque appartement dispose d''une place de parking en sous-sol. La résidence compte également une magnifique piscine commune entourée de beaux jardins. Prix: à partir de 625.000 ? hors frais Penthouse: à partir de 895.000 ? hors frais Inclus: électroménagers', '', '', 625000, 'las-colinas-superbes-appartements-3-chambres-dans-un-golf-exclusif', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1955', 'Fuente Alamo: belles villas en 3 chambres', '', '', 'Ces nouvelles villas sont situées à La Pinilla de Fuente Alamo, dans la région de Murcie. Cet emplacement offre un cadre naturel exceptionnel, loin de l''agitation des grandes villes et de la pression touristique de la côte. Ce nouveau projet privilégie l''efficacité énergétique, l''utilisation de matériaux respectueux de l''environnement et l''intégration harmonieuse dans l''environnement rural. Fuente Alamo est situé à 22 km au nord-ouest de Carthagène et à 35 km au sud-ouest de Murcie. La ville se trouve dans le bassin de la Mar Menor, entourée des montagnes d''Algarrobo, Los Gómez, Los Victorias et du Carrascoy. Fuente Álamo se trouve à 30 minutes de l''aéroport de Murcie-Corvera et à 26 km des belles plages de Bolnuevo. - Villas 3 chambres et 2 salles de bains - Cuisine ouverte et living lumineux - Solarium de 83 m² - Piscine privée (2.5 m² x 4.5 m²) Prix: à partir de 254.730 ? hors frais', '', '', 254730, 'fuente-alamo-belles-villas-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1956', 'Los Alcazares: beaux appartements 2 chambres dans un golf prestigieux', '', '', 'Bienvenue dans un complexe résidentiel d?exception situé à Los Alcázares, l''une des destinations les plus prisées de la Costa Cálida. À seulement 800 mètres des plages paisibles de la Mar Menor et à quelques minutes à pied du centre-ville, cet ensemble bénéficie d?un emplacement privilégié, à proximité immédiate des commerces, restaurants et services du quotidien. ce complexe est idéal pour les amateurs de sports nautiques ou de farniente en bord de mer. Paddle, voile, baignade ou golf : ici, tout est à portée de main, toute l?année. Installé dans un cadre naturel remarquable, face au prestigieux Serena Golf et offrant des vues imprenables sur la Mar Menor ? la plus vaste lagune d''eau salée d''Europe ? ce quartier paisible conjugue nature, confort et raffinement. La résidence se compose de 30 logements modernes, de 2 ou 3 chambres, pensés pour répondre aux attentes les plus exigeantes en matière de confort et de design. Vous pouvez choisir parmi : - Rez-de-chaussée avec jardin privatif - Étage intermédiaire avec vaste terrasse - Penthouses avec solarium privé et vue panoramique Distances clés : - Plage (Mar Menor) ? 800 m - Serena Golf ? jouxtant le complexe - Centre de Los Alcázares ? 1 km - Aéroport de Murcie (Corvera) ? 30 km (env. 25 min) - Aéroport d?Alicante ? 90 km (env. 55 min) - Carthagène ? 22 km - Murcie ? 40 km Prix: à partir de 279.900 ? hors frais Fin des travaux: décembre 2027 ou mars 2028', '', '', 279900, 'los-alcazares-beaux-appartements-2-chambres-dans-un-golf-prestigieux', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1957', 'Los Alcazares: superbes appartements 3 chambres dans un golf prestigieux', '', '', 'Bienvenue dans un complexe résidentiel d?exception situé à Los Alcázares, l''une des destinations les plus prisées de la Costa Cálida. À seulement 800 mètres des plages paisibles de la Mar Menor et à quelques minutes à pied du centre-ville, cet ensemble bénéficie d?un emplacement privilégié, à proximité immédiate des commerces, restaurants et services du quotidien. ce complexe est idéal pour les amateurs de sports nautiques ou de farniente en bord de mer. Paddle, voile, baignade ou golf : ici, tout est à portée de main, toute l?année. Installé dans un cadre naturel remarquable, face au prestigieux Serena Golf et offrant des vues imprenables sur la Mar Menor ? la plus vaste lagune d''eau salée d''Europe ? ce quartier paisible conjugue nature, confort et raffinement. La résidence se compose de 30 logements modernes, de 2 ou 3 chambres, pensés pour répondre aux attentes les plus exigeantes en matière de confort et de design. Vous pouvez choisir parmi : - Rez-de-chaussée avec jardin privatif - Étage intermédiaire avec vaste terrasse - Penthouses avec solarium privé et vue panoramique Distances clés : - Plage (Mar Menor) ? 800 m - Serena Golf ? jouxtant le complexe - Centre de Los Alcázares ? 1 km - Aéroport de Murcie (Corvera) ? 30 km (env. 25 min) - Aéroport d?Alicante ? 90 km (env. 55 min) - Carthagène ? 22 km - Murcie ? 40 km Prix: à partir de 319.900 ? hors frais Fin des travaux: décembre 2027 ou mars 2028', '', '', 319900, 'los-alcazares-superbes-appartements-3-chambres-dans-un-golf-prestigieux', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1959', 'Bonalba Golf : superbes appartements 2 chambres', '', '', 'Ce nouveau complexe résidentiel se situe sur le terrain de golf de Bonalba, situation privilégiée à quelques minutes de Mutxamel, d''El Campello, de la ville d''Alicante, des plages, des supermarchés, des centres commerciaux, des restaurants, de l''université, de l''hôpital et de l''aéroport international. La résidence offre une vue imprenable sur la mer. Le complexe propose des appartements 2 et 3 chambres avec de belles grandes terrasses, ainsi que des villas individuelles 2, 3 ou 4 chambres. Superbe piscine commune. Les appartements 2 chambres disposent de 2 salles de bains et d''une cuisine ouverte donnant sur le living avec baies vitrées vers la terrasse. Place de parking en souterrain et cave. Prix: à partir de 266.000 ? hors frais', '', '', 266000, 'bonalba-golf-superbes-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1960', 'El Verger: jolies maisons 2 chambres à 500 m de la mer', '', '', 'A El Verger, non loin de Denia, cette nouvelle résidence est située à 500 m de la mer et à proximité de nombreuses facilités, telles que supermarchés, bars, restaurants... La résidence compte 65 logements, répartis en appartements 2 chambres et maisons 2 chambres. Les maisons sont agencées sur 2 niveaux et comptent 2 chambres et 1 ou 2 salles de bains. Possibilité de placer une piscine privée en fonction de la superficie du jardin. Les espaces communs offrent un cadre idéal pour les loisirs, la détente et la vie active : - Sentiers de promenade et pistes cyclables - Espaces verts paysagers - Zone sportive - Grande piscine - Salle de sport toute équipée - Sauna pour vous détendre - Club social pour se retrouver en famille ou entre amis - Point plage : un espace exclusif en bord de mer pour les résidents Le Point Plage est un atout unique de ce projet. Situé directement sur la plage de La Almadraba, il offre aux résidents : - Un lieu pour organiser des événements privés - Des installations pour garer les vélos et stocker le matériel nautique - Une douche extérieure et une petite piscine pour se rafraîchir après la baignade Ce projet met l?accent sur l?efficacité énergétique et l?utilisation d?énergies renouvelables, pour réduire votre empreinte carbone tout en maximisant votre confort au quotidien. Prix: Maisons 2 chambres à partir de 357.000 ? hors frais', '', '', 357000, 'el-verger-jolies-maisons-2-chambres-a-500-m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1961', 'Monforte del Cid : belles villas modernes en 3 chambres', '', '', 'Ces villas sont idéalement situées à Monforte del Cid, à seulement 3 minutes du terrain de golf Alenda et à proximité des villes d''Alicante et d''Elche. Vous pourrez profiter d''une riche offre culturelle, gastronomique et de divertissement, ainsi que des magnifiques plages de sable doré de la Méditerranée, parfaites pour des journées ensoleillées. Les villas se trouvent dans une urbanisation tranquille, à seulement 12 minutes de l''aéroport d''Alicante-Elche. Caractéristiques des villas : - Villas de plain-pied. - Parcelles : À partir de 618m², offrant un vaste espace extérieur. - Disposition : Zone de jour : Un grand salon-salle à manger avec une cuisine ouverte, communiquant avec un porche moderne grâce à de grandes fenêtres. Cet espace lumineux est idéal pour profiter de l''extérieur. Une buanderie est également présente. Zone de nuit : Trois chambres, dont une suite parentale avec dressing et salle de bains attenante. Une deuxième salle de bains dessert les autres chambres. À 15 minutes en voiture d''Elche et d''Alicante, ainsi que de l''aéroport et des meilleures plages. Environnement : Situé dans un cadre paisible à proximité du terrain de golf Alenda. Prix: à partir de 368.000 ? hors frais Inclus: piscine 3m x 6m', '', '', 368000, 'monforte-del-cid-belles-villas-modernes-en-3-chambres-2', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1962', 'Estepona : superbes appartements 2 chambres sur le golf de Valle Romano', '', '', 'Nouveau complexe résidentiel exclusif composé de 144 logements de 1, 2 et 3 chambres, répartis dans six immeubles de faible hauteur. Son design avant-gardiste et moderne s''intègre parfaitement à l''environnement naturel, offrant à ses résidents une vue spectaculaire sur la baie d''Estepona et le terrain de golf de Valle Romano. L''orientation sud des logements garantit à tous une excellente luminosité, tirant ainsi le meilleur parti des heures d''ensoleillement naturel. Les grandes baies vitrées permettent non seulement de profiter de la vue panoramique, mais créent également une atmosphère lumineuse et spacieuse, renforçant ainsi la sensation de confort. Les salons, conçus pour créer une connexion fluide avec l''extérieur, accentuent l''impression d''espace. Le complexe résidentiel dispose d''une gamme complète de services, notamment une piscine, une salle de sport intérieure et une salle gastronomique. De plus, les résidents peuvent profiter de vastes espaces verts avec des espèces indigènes qui mettent en valeur la beauté naturelle de la région. La sécurité et l''intimité sont prioritaires, c''est pourquoi le complexe est fermé et surveillé par un poste de sécurité, garantissant tranquillité et exclusivité. Garage et débarras inclus dans le prix. Prix: à partir de 296.000 ? hors frais Livraison: mai 2028', '', '', 296000, 'estepona-superbes-appartements-2-chambres-sur-le-golf-de-valle-romano', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1963', 'Mijas: superbes apparteemnts de standing en 2 chambres', '', '', 'Cette nouvelle résidence bénéficie d''un emplacement stratégique entre les villes côtières de Fuengirola et Mijas, dans la région dynamique de Las Lagunas. Ce quartier est le plus moderne, commercial et animé de Mijas. L''offre de services et de commerces est imbattable. Juste en face du complexe se trouve le parc commercial Miramar, et à seulement 10 minutes à pied, le grand centre commercial et de loisirs du même nom. De plus, en à peine cinq minutes en voiture, vous pouvez rejoindre le centre de Fuengirola, une ville réputée pour son offre variée de divertissements. Grâce à son emplacement privilégié, Las Lagunas se trouve à moins d''une demi-heure de Marbella et de Malaga, deux villes à l''ambiance cosmopolite. Cela fait de ce projet immobilier un point névralgique au c?ur de la Costa del Sol. La résidence se distingue par une architecture impeccable, alliant design contemporain et élégance. Son charme sophistiqué se reflète dans chaque détail, de ses lignes avant-gardistes à ses vastes terrasses. Les équipements innovants, soigneusement conçus par des professionnels de l''hôtellerie, transforment les espaces communs en lieux exclusifs qui offrent à leurs résidents le privilège de vivre dans le confort et le raffinement d''un hôtel. Chaque recoin a été pensé pour favoriser le bien-être, la détente et la socialisation dans un environnement unique. Le complexe dispose de deux piscines extérieures, d''un spectaculaire espace rooftop avec skypool, d''un spa complet pour se détendre et se déconnecter, d''une salle de sport entièrement équipée, d''un espace de coworking moderne et de jardins luxuriants méticuleusement entretenus, créant une oasis de tranquillité au c?ur de la Costa del Sol. Les sols en grès cérame grand format imitation bois apportent continuité et chaleur à l''ensemble du logement, tandis que les grandes baies vitrées inondent les pièces de lumière naturelle. Les cuisines ouvertes ont été conçues pour maximiser la fonctionnalité, en combinant des finitions de haute qualité avec des appareils électroménagers Miele, sans renoncer à l''esthétique moderne et élégante. Chaque appartement dispose également d''une place de parking et d''un débarras en sous-sol. De plus, la promotion intègre des installations intelligentes tant à l''intérieur des logements que dans les parties communes, garantissant un foyer efficace et connecté. Tout cela, associé à la meilleure certification énergétique BREEAM, assure un style de vie durable et avant-gardiste. Prix: 2 chambres à partir de 405.000 ? hors frais Fin des travaux : 4T2027', '', '', 405000, 'mijas-superbes-apparteemnts-de-standing-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1964', 'Mijas: superbes apparteemnts de standing en 3 chambres', '', '', 'Cette nouvelle résidence bénéficie d''un emplacement stratégique entre les villes côtières de Fuengirola et Mijas, dans la région dynamique de Las Lagunas. Ce quartier est le plus moderne, commercial et animé de Mijas. L''offre de services et de commerces est imbattable. Juste en face du complexe se trouve le parc commercial Miramar, et à seulement 10 minutes à pied, le grand centre commercial et de loisirs du même nom. De plus, en à peine cinq minutes en voiture, vous pouvez rejoindre le centre de Fuengirola, une ville réputée pour son offre variée de divertissements. Grâce à son emplacement privilégié, Las Lagunas se trouve à moins d''une demi-heure de Marbella et de Malaga, deux villes à l''ambiance cosmopolite. Cela fait de ce projet immobilier un point névralgique au c?ur de la Costa del Sol. La résidence se distingue par une architecture impeccable, alliant design contemporain et élégance. Son charme sophistiqué se reflète dans chaque détail, de ses lignes avant-gardistes à ses vastes terrasses. Les équipements innovants, soigneusement conçus par des professionnels de l''hôtellerie, transforment les espaces communs en lieux exclusifs qui offrent à leurs résidents le privilège de vivre dans le confort et le raffinement d''un hôtel. Chaque recoin a été pensé pour favoriser le bien-être, la détente et la socialisation dans un environnement unique. Le complexe dispose de deux piscines extérieures, d''un spectaculaire espace rooftop avec skypool, d''un spa complet pour se détendre et se déconnecter, d''une salle de sport entièrement équipée, d''un espace de coworking moderne et de jardins luxuriants méticuleusement entretenus, créant une oasis de tranquillité au c?ur de la Costa del Sol. Les sols en grès cérame grand format imitation bois apportent continuité et chaleur à l''ensemble du logement, tandis que les grandes baies vitrées inondent les pièces de lumière naturelle. Les cuisines ouvertes ont été conçues pour maximiser la fonctionnalité, en combinant des finitions de haute qualité avec des appareils électroménagers Miele, sans renoncer à l''esthétique moderne et élégante. Chaque appartement dispose également d''une place de parking et d''un débarras en sous-sol. De plus, la promotion intègre des installations intelligentes tant à l''intérieur des logements que dans les parties communes, garantissant un foyer efficace et connecté. Tout cela, associé à la meilleure certification énergétique BREEAM, assure un style de vie durable et avant-gardiste. Prix: 3 chambres à partir de 485.000 ? hors frais Fin des travaux: 4T2027', '', '', 485000, 'mijas-superbes-apparteemnts-de-standing-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1967', 'Vera: beaux appartements 2 chambres proches des plages', '', '', 'Située à seulement 2 km des magnifiques plages de Vera Playa, cette nouvelle résidence vous offre un cadre de vie contemporain, paisible et ensoleillé toute l?année. Profitez de vues dégagées sur la mer, d?un environnement verdoyant, et de prestations haut de gamme dans une zone résidentielle très prisée de la Costa de Almería. Ce complexe propose 60 appartements répartis dans 5 petits immeubles à faible densité (deux logements par étage), disponibles en 2 ou 3 chambres. Chaque logement a été conçu pour offrir un équilibre parfait entre design moderne, confort et fonctionnalité. Vous avez le choix entre : - Rez-de-chaussée avec jardin privatif - Appartements intermédiaires avec grandes terrasses - Penthouses avec solarium privé, cuisine d?été et pergola Les appartements disposent d''une cuisine ouverte entièrement équipée (réfrigérateur encastré, four, micro-ondes, plaque à induction, hotte, lave-vaisselle), de 2 salles de bains modernes avec douche à l?italienne, parois en verre, meubles intégrés et sèche-serviettes, d''un emplacement de parking au sous-sol avec cave privée. La résidence offre deux piscines extérieures et une piscine intérieure chauffée pour nager toute l?année Pré-installation pour borne de recharge de véhicules électriques. Vera Playa séduit par ses plages étendues, son ambiance conviviale et sa proximité avec toutes les commodités : - Plage : à 2 km - Golf Desert Springs : à 8 km - Centre-ville de Vera : à 5 km - Port de Garrucha : à 6 km - Parc commercial de Mojácar : à 10 km Prix: à partir de 225.000 ? hors frais Livraison: juin 2027', '', '', 225000, 'vera-beaux-appartements-2-chambres-proches-des-plages', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1968', 'Vera: beaux appartements 3 chambres proches des plages', '', '', 'Située à seulement 2 km des magnifiques plages de Vera Playa, cette nouvelle résidence vous offre un cadre de vie contemporain, paisible et ensoleillé toute l?année. Profitez de vues dégagées sur la mer, d?un environnement verdoyant, et de prestations haut de gamme dans une zone résidentielle très prisée de la Costa de Almería. Ce complexe propose 60 appartements répartis dans 5 petits immeubles à faible densité (deux logements par étage), disponibles en 2 ou 3 chambres. Chaque logement a été conçu pour offrir un équilibre parfait entre design moderne, confort et fonctionnalité. Vous avez le choix entre : - Rez-de-chaussée avec jardin privatif - Appartements intermédiaires avec grandes terrasses - Penthouses avec solarium privé, cuisine d?été et pergola Les appartements disposent d''une cuisine ouverte entièrement équipée (réfrigérateur encastré, four, micro-ondes, plaque à induction, hotte, lave-vaisselle), de 2 salles de bains modernes avec douche à l?italienne, parois en verre, meubles intégrés et sèche-serviettes, d''un emplacement de parking au sous-sol avec cave privée. La résidence offre deux piscines extérieures et une piscine intérieure chauffée pour nager toute l?année Pré-installation pour borne de recharge de véhicules électriques. Vera Playa séduit par ses plages étendues, son ambiance conviviale et sa proximité avec toutes les commodités : - Plage : à 2 km - Golf Desert Springs : à 8 km - Centre-ville de Vera : à 5 km - Port de Garrucha : à 6 km - Parc commercial de Mojácar : à 10 km Prix: 3 chambres à partir de 255.000 ? hors frais Livraison: juin 2027', '', '', 255000, 'vera-beaux-appartements-3-chambres-proches-des-plages', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1969', 'Vera: appartements modernes en 2 chambres proches des plages', '', '', 'Découvrez une nouvelle résidence haut de gamme à Vera Playa. Située à seulement 2 km des plages de sable fin, cette promotion vous propose un cadre de vie moderne et serein, idéal pour y vivre toute l?année ou profiter de vacances au soleil. Cette résidence se compose de 18 appartements contemporains, disponibles en 2 ou 3 chambres, pensés pour allier design, fonctionnalité et confort. Les appartements 2 chambres sont situés au 1er étage et jouissent d''une belle terrasse de 22m² et d''un grand solarium de 65 m² avec cuisine d?été et pergola. Les appartements disposent d''une cuisine ouverte entièrement équipée (réfrigérateur, lave-vaisselle, plaque à induction, four, micro-ondes, hotte), des espaces de vie lumineux, deux salles de bains modernes avec paroi de douche en verre, meuble vasque et sèche-serviettes, d''une place de parking et d''un débarras. Belle piscine commune. Vera Playa est réputée pour son ambiance décontractée et ses plages étendues. La résidence offre un accès rapide aux commodités suivantes: - Plage : 2 km - Golf Desert Springs : 8 km - Centre de Vera : 5 km - Port de Garrucha : 6 km - Centre commercial Mojácar : 10 km Prix: 2 chambres avec solarium : à partir de 298.500 ? hors frais Livraison: novembre 2027', '', '', 298500, 'vera-appartements-modernes-en-2-chambres-proches-des-plages', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1970', 'Vera: appartements modernes en 3 chambres proches des plages', '', '', 'Découvrez une nouvelle résidence haut de gamme à Vera Playa. Située à seulement 2 km des plages de sable fin, cette promotion vous propose un cadre de vie moderne et serein, idéal pour y vivre toute l?année ou profiter de vacances au soleil. Cette résidence se compose de 18 appartements contemporains, disponibles en 2 ou 3 chambres, pensés pour allier design, fonctionnalité et confort. Les appartements 3 chambres sont situés au rez-de-chaussée et jouissent de 2 belles terrasses, à l''avant et à l''arrière. Les appartements disposent d''une cuisine ouverte entièrement équipée (réfrigérateur, lave-vaisselle, plaque à induction, four, micro-ondes, hotte), des espaces de vie lumineux, deux salles de bains modernes avec paroi de douche en verre, meuble vasque et sèche-serviettes, d''une place de parking et d''un débarras. Belle piscine commune. Vera Playa est réputée pour son ambiance décontractée et ses plages étendues. La résidence offre un accès rapide aux commodités suivantes: - Plage : 2 km - Golf Desert Springs : 8 km - Centre de Vera : 5 km - Port de Garrucha : 6 km - Centre commercial Mojácar : 10 km Prix: 3 chambres au rez-de-chaussée : à partir de 268.500 ? hors frais Livraison: novembre 2027', '', '', 268500, 'vera-appartements-modernes-en-3-chambres-proches-des-plages', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1981', 'Los Alcazares: superbes villas 3 chambres de style méditérranéen', '', '', 'Ces nouvelles villas se situent à La Serena Golf, dans la commune de Los Alcázares, un environnement privilégié de la Costa Cálida, à seulement 25 minutes de l''aéroport de Murcie et à 55 minutes de l''aéroport d''Alicante. La zone est reliée par autoroute à Carthagène, Murcie et Alicante. Ce quartier paisible conjugue nature, confort et raffinement. Il s''agit d''un emplacement privilégié, à proximité immédiate des commerces, restaurants et services du quotidien. Les belles plages de la Mar Menor sont toutes proches, ce qui en fait l''endroit idéal pour les amateurs de sports nautiques ou de farniente en bord de mer. Paddle, voile, baignade ou golf : ici, tout est à portée de main, toute l?année. Les villas sont orientées sud et allient design méditerranéen, qualité et fonctionnalité. Elles disposent de 3 chambres, de 2 salles de bains, de belles terrasses, d''une piscine privée et d''une place de parking. Prix: à partir de 399.900 ? hors frais Inclus: - volets électriques dans les chambres - éclairage intérieur et extérieur Solarium possible moyennant supplément : 17.500 ? Fin des travaux: décembre 2026', '', '', 399900, 'los-alcazares-superbes-villas-3-chambres-de-style-mediterraneen', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1987', 'Hacienda del Alamo - Murcie: superbes villas avec picine privée', '', '', 'Découvrez des villas modernes, élégantes au c?ur du prestigieux Hacienda del Álamo Golf Resort, idéalement situé entre Carthagène et Murcie, sur la magnifique Costa Cálida. Profitez d?un cadre unique, combinant golf, loisirs et vie de famille. Les villas disposent de 3 chambres et 2 salles de bains, d''un solarium privé sur le toit. Avec des parcelles à partir de 396 m² et une surface construite de 111 m², elles offrent un espace généreux pour la vie intérieure et extérieure. Les villas sont équipées de tout le confort moderne : - Jardin avec système d?irrigation automatique - Cuisine entièrement équipée avec placards et électroménagers inclus - Salles de bains élégantes avec meubles, miroirs et parois de douche - Piscine privée de 3x6 m avec douche Accès à une grande piscine communautaire et aire de jeux pour enfants Hacienda del Álamo est connu pour être l''un des meilleurs complexes touristiques de golf d''Espagne, offrant à ses résidents un style de vie détendu, sportif et confortable. - Parcours de golf 18 trous et académie de golf professionnelle - Installations sportives : tennis, paddle, salle de sport et cours de fitness - Club-house avec vue panoramique, restaurant méditerranéen et terrasses ensoleillées - Hôtel et spa 4 étoiles pour le bien-être et la relaxation - Espaces pour toute la famille : aires de jeux, piscines et pistes cyclables - Village espagnol traditionnel avec boutiques, cafés et restaurants Prix: à partir de 335.600 ? hors frais', '', '', 335600, 'hacienda-del-alamo-murcie-superbes-villas-avec-picine-privee', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1971', 'Hondón de las Nieves: superbes villa 3 chambres', '', '', 'Offrez-vous le confort et l?élégance d?un cadre de vie exceptionnel avec ces magnifiques villas de plain-pied. Indépendantes et soigneusement conçues, elles allient modernité, fonctionnalité et bien-être. Chaque villa dispose d?un jardin privatif idéal pour créer votre propre oasis de tranquillité. Profitez pleinement des journées ensoleillées en vous rafraîchissant dans votre piscine privée, en toute intimité. La propriété s?organise autour de deux espaces distincts : - Espace jour : un vaste salon-salle à manger avec cuisine américaine, baigné de lumière grâce à deux grandes baies vitrées. Celles-ci s?ouvrent sur un espace extérieur aménagé avec piscine. Une buanderie, complète cette zone. - Espace nuit : vous y trouverez trois chambres, dont une suite parentale avec dressing spacieux et salle de bains privative. Une seconde salle de bains dessert les autres chambres. Implantées dans un quartier résidentiel paisible, ces villas vous assurent calme et intimité, tout en restant proches de toutes les commodités : commerces, supermarchés, restaurants et services essentiels. Située à Hondón de las Nieves, charmante commune de la Communauté valencienne (sud-ouest de la province d?Alicante, région du Vinalopó Medio), cette urbanisation vous offre un environnement naturel agréable et connecté. Les plages et l?aéroport international d?Alicante se trouvent à seulement 30 minutes en voiture. Prix: à partir de 289.900 ? hors frais', '', '', 289900, 'hondon-de-las-nieves-superbes-villa-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1974', 'Punta Prima: appartements 3 chambres à seulement 250 m de la mer', '', '', 'Découvrez ce nouveau complexe résidentiel moderne à Punta Prima, l?un des quartiers les plus recherchés de Torrevieja. Idéalement situé à seulement 250 mètres de la plage, ce projet unique vous offre le privilège de vivre à deux pas de la mer, dans un environnement sécurisé et entièrement pensé pour votre confort. Le complexe propose 250 appartements aux finitions soignées, disponibles en 2 ou 3 chambres avec 2 salles de bains. Tous les logements disposent d?une cuisine ouverte intégrée au séjour, créant un espace de vie spacieux et baigné de lumière naturelle. Les appartements au rez-de-chaussée disposent d''un jardin privatif, les étages intermédiaires de grandes belles terrasses et les penthouses d''un solarium privatif pour profiter du soleil toute l?année. Chaque appartement est vendu avec une place de parking et un débarras. La résidence comprend de nombreux équipements pour toute la famille : - Trois piscines, dont une chauffée - Une salle de sport avec jacuzzi - Un court de paddle et un terrain de pétanque - Jardins paysagers - Aire de jeux et piscine pour enfants - Parking à vélos Chaque logement est équipé de prestations de qualité : - Menuiserie extérieure en PVC - Double vitrage et volets roulants motorisés dans les chambres - Cuisine aménagée avec électroménagers inclus - Salles de bains équipées (paroi de douche, meuble vasque, miroir, chauffage au sol) - Climatisation par pompe à chaleur aérothermique - Porte d?entrée blindée Situé à seulement 5 km du centre de Torrevieja, Punta Prima bénéficie d?infrastructures complètes : - Plage de Punta Prima : 250 m - Centre commercial La Zenia Boulevard : 4 km - Golf de Villamartín : 7 km - Hôpital universitaire de Torrevieja : 3 km - Port de plaisance de Torrevieja : 6 km - Aéroport international d?Alicante : 45 km Prix: à partir de 359.000 ? hors frais Fin des travaux: septembre 2027', '', '', 359000, 'punta-prima-appartements-3-chambres-a-seulement-250-m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1976', 'Mar de Cristal : superbes appartements 3 chambres à 500 m de la mer', '', '', 'Découvrez ce magnifique complexe résidentiel moderne situé à quelques pas de la promenade et des superbes plages de sable de Mar de Cristal, sur la Costa Cálida. Ce projet offre un choix varié de logements : - Appartements en rez-de-chaussée avec jardin privé, - Appartements à l?étage avec terrasse spacieuse, - Penthouses avec solarium privé offrant une vue imprenable Chaque propriété dispose de 3 chambres et de 2 salles de bains, dont une attenante à la suite parentale. Le design contemporain met à l?honneur des espaces de vie ouverts, avec une cuisine moderne intégrée au salon et à la salle à manger, et un accès vers une grande terrasse. Les logements sont construits avec des matériaux de haute qualité, et comprennent un local de rangement ainsi qu''une place de parking souterrain. Le complexe bénéficie d?un emplacement idéal, à proximité immédiate de toutes les commodités : supermarchés, restaurants, bars, centre de tennis, marina, etc. À seulement quelques minutes en voiture, vous découvrirez : - Le parc naturel de Calblanque et ses plages sauvages, - Le célèbre La Manga Club, - Le village animé de Los Belones. Les aéroports de Murcie (25 min) et d?Alicante (1 h) assurent une excellente connectivité. Les villes historiques de Carthagène et Murcie sont également facilement accessibles pour des escapades culturelles. Prix: - à partir de 360.000 ? hors frais - Penthouses : 595.000 ? hors frais Fin des travaux: juillet 2026', '', '', 360000, 'mar-de-cristal-superbes-appartements-3-chambres-a-500-m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
